module RefModule(
    input wire clk,
    input wire reset,
    input wire load,
    input wire [15:0] data_in,
    output reg [15:0] q
    );
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk or posedge reset) begin
    if (reset) begin
        q <= 16'b0000000000000000;
    end else if (load) begin
        q <= data_in;
    end
end

endmodule
